module float_multi(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

    reg [2:0] counter;
    reg [23:0] a_mantissa, b_mantissa, z_mantissa;
    reg [9:0] a_exponent, b_exponent, z_exponent;
    reg a_sign, b_sign, z_sign;
    reg [49:0] product;
    reg guard_bit, round_bit, sticky;

    always @(posedge clk) begin
        if (rst) begin
            counter <= 0;
            z <= 0;
        end else begin
            case (counter)
                // Stage 0: Extract fields from inputs
                3'd0: begin
                    a_mantissa <= {1'b1, a[22:0]};
                    b_mantissa <= {1'b1, b[22:0]};
                    a_exponent <= {2'b00, a[30:23]};
                    b_exponent <= {2'b00, b[30:23]};
                    a_sign <= a[31];
                    b_sign <= b[31];
                    counter <= 1;
                end

                // Stage 1: Handle special cases and start multiplication
                3'd1: begin
                    z_sign <= a_sign ^ b_sign;

                    // Check for NaN
                    if ((a_exponent == 10'hFF && a_mantissa[22:0] != 0) ||
                        (b_exponent == 10'hFF && b_mantissa[22:0] != 0)) begin
                        z <= 32'h7FC00000; // NaN
                        counter <= 0;
                    end
                    // Check for infinity
                    else if (a_exponent == 10'hFF || b_exponent == 10'hFF) begin
                        // Check if other operand is zero
                        if ((a_exponent == 10'h00 && a_mantissa[22:0] == 0) ||
                            (b_exponent == 10'h00 && b_mantissa[22:0] == 0)) begin
                            z <= 32'h7FC00000; // NaN (inf * 0)
                        end else begin
                            z <= {z_sign, 8'hFF, 23'h0}; // Infinity
                        end
                        counter <= 0;
                    end
                    // Check for zero
                    else if ((a_exponent == 10'h00 && a_mantissa[22:0] == 0) ||
                             (b_exponent == 10'h00 && b_mantissa[22:0] == 0)) begin
                        z <= {z_sign, 31'h0}; // Zero
                        counter <= 0;
                    end
                    else begin
                        // Normal multiplication
                        z_exponent <= a_exponent + b_exponent - 10'd127;
                        product <= a_mantissa * b_mantissa;
                        counter <= 2;
                    end
                end

                // Stage 2: Normalize the product
                3'd2: begin
                    if (product[47]) begin
                        // Product is normalized (MSB at bit 47)
                        z_mantissa <= product[47:24];
                        guard_bit <= product[23];
                        round_bit <= product[22];
                        sticky <= |product[21:0];
                        z_exponent <= z_exponent + 1;
                    end else begin
                        // Product MSB at bit 46
                        z_mantissa <= product[46:23];
                        guard_bit <= product[22];
                        round_bit <= product[21];
                        sticky <= |product[20:0];
                    end
                    counter <= 3;
                end

                // Stage 3: Round the result
                3'd3: begin
                    // Round to nearest even
                    if (guard_bit && (round_bit || sticky || z_mantissa[0])) begin
                        z_mantissa <= z_mantissa + 1;
                        if (z_mantissa == 24'hFFFFFF) begin
                            z_exponent <= z_exponent + 1;
                        end
                    end
                    counter <= 4;
                end

                // Stage 4: Handle overflow/underflow and generate output
                3'd4: begin
                    // Check for overflow
                    if (z_exponent >= 10'hFF) begin
                        z <= {z_sign, 8'hFF, 23'h0}; // Infinity
                    end
                    // Check for underflow
                    else if (z_exponent <= 0) begin
                        z <= {z_sign, 31'h0}; // Zero (underflow)
                    end
                    else begin
                        z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                    end
                    counter <= 0;
                end

                default: begin
                    counter <= 0;
                end
