module LIFObuffer(
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];
    reg [2:0] SP;

    integer i;

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                SP <= 3'd4;
                dataOut <= 4'b0000;
                for (i = 0; i < 4; i = i + 1) begin
                    stack_mem[i] <= 4'b0000;
                end
                EMPTY <= 1'b1;
                FULL <= 1'b0;
            end
            else begin
                if (RW == 1'b0 && !FULL) begin
                    // Write operation (push)
                    SP <= SP - 1;
                    stack_mem[SP - 1] <= dataIn;
                end
                else if (RW == 1'b1 && !EMPTY) begin
                    // Read operation (pop)
                    dataOut <= stack_mem[SP];
                    stack_mem[SP] <= 4'b0000;
                    SP <= SP + 1;
                end

                // Update flags
                if (SP == 3'd4) begin
                    EMPTY <= 1'b1;
                    FULL <= 1'b0;
                end
                else if (SP == 3'd1 && RW == 1'b0 && !FULL) begin
                    EMPTY <= 1'b0;
                    FULL <= 1'b1;
                end
