module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

    // Parameter for 3.5x division (multiply by 2 = 7 cycles)
    parameter MUL2_DIV_CLK = 7;

    // Counter
    reg [2:0] cnt;

    // Intermediate clock signals
    reg clk_div1;
    reg clk_div2;

    // Counter logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 3'd0;
        end else begin
            if (cnt == MUL2_DIV_CLK - 1)
                cnt <= 3'd0;
            else
                cnt <= cnt + 1'b1;
        end
    end

    // Generate first divided clock (posedge triggered)
    // High for 4 cycles (0,1,2,3), Low for 3 cycles (4,5,6)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div1 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div1 <= 1'b1;
            else if (cnt == 3'd3)
                clk_div1 <= 1'b0;
            else
                clk_div1 <= clk_div1;
        end
    end

    // Generate second divided clock (negedge triggered, phase shifted by half cycle)
    // This creates a half-period shifted version
    always @(negedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div2 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div2 <= 1'b1;
            else if (cnt == 3'd3)
                clk_div2 <= 1'b0;
            else
                clk_div2 <= clk_div2;
        end
    end

    // OR the two clocks to get the final fractional divided clock
    assign clk_div = clk_div1 | clk_div2;

endmodule

